+    const url = normalizeHttpUrlCandidate(command) ?? command;
+    return {
+      name,
+      description,
+      command: {
+        kind: 'http',
+        url: new URL(url),
+      },
+      source: { kind: 'local', path: '<adhoc>' },
+    };
+  }
+  return {
+    name,
+    description,
+    command: {
+      kind: 'stdio',
+      command: command.command,
+      args: command.args ?? [],
+    },
+    source: { kind: 'local', path: '<adhoc>' },
+  };
